INSERT INTO `support` (`id`, `category`, `question`, `answer`, `created_at`) VALUES
(1, 'Getting Started', 'What is the Reward Point System (RPS)?', 'The RPS encourages collaboration, teamwork, and everyday contributions by awarding points for meaningful efforts. It fosters an inclusive culture where every contribution is recognized, promoting gratitude, continuous learning, and visible engagement.', '2026-01-13 04:17:01'),
(2, 'Getting Started', 'Who is eligible for the RPS?', 'All permanent team members with LP portal access are eligible. Interns and contractual members are not eligible for the point system.', '2026-01-13 04:17:01'),
(3, 'Getting Started', 'How do I access my RPS dashboard?', 'Login to TeamYPL portal using your employee ID and password. Navigate to the \"RPS\" tab in the main navigation to view your dashboard with points balance, leaderboard, and transaction history.', '2026-01-13 04:17:01'),
(4, 'Earning Points', 'How can I earn points?', 'You can earn points through: Awareness visits (20-40 points), Event participation (30-70 points), Social causes (50-100 points), Kaizen submissions (50-200 points), Cross-sangh collaboration (100-200 points), Pakka Maitri contributions (50-100 points), Skill development (100-200 points), Leading new initiatives (200-400 points), and Wellness participation (20-50 points).', '2026-01-13 04:17:01'),
(5, 'Earning Points', 'What is the maximum number of points I can earn in a year?', 'The maximum cap is 50,000 points per year. This cap only applies to points awarded by leaders or peers. Points earned through events, achievements, or extra work are not capped. If you exceed 50,000 points, additional points become bonus/overflow points allowing multiple redemptions.', '2026-01-13 04:17:01'),
(6, 'Earning Points', 'Do points from events count towards my annual cap?', 'No, points earned through events, achievements, or extra work are NOT capped and do not count towards your 50,000 annual limit. Only peer-to-peer transfers and leader allocations count towards the cap.', '2026-01-13 04:17:01'),
(7, 'Gifting Points', 'Can I gift points to my colleagues?', 'Yes! Point transfers are allowed, working like UPI transfers to build gratitude and collaboration. Leaders (Sanghrakshaks or Sevaks) can transfer point to their team members (Utpadaks or Sevaks), and Sevaks can transfer to Utpadaks. Transfers between same designation or upwards are not allowed.', '2026-01-13 04:17:01'),
(8, 'Gifting Points', 'What are the limits for gifting points?', 'Transfer caps by designation: Sanghrakshak → Utpadak (150-200 points), Sevak → Utpadak (300-500 points), Sevak → Sanghrakshak (500-800 points).', '2026-01-13 04:17:01'),
(9, 'Gifting Points', 'Can I recall or cancel points after sending them?', 'No, once points are sent, they cannot be recalled or cancelled. Please verify the recipient and amount carefully before confirming the transfer.', '2026-01-13 04:17:01'),
(10, 'Gifting Points', 'Why can\'t I transfer points to my leader?', 'Transfers to leaders (Sanghrakshaks or Sevaks) are not permitted to maintain the integrity of the recognition system. Points should flow from leadership to team members as recognition, not the reverse.', '2026-01-13 04:17:01'),
(11, 'Redemption', 'How do I redeem my points?', 'Click the \"Redeem Points\" button on your dashboard to access the Pakka Merch Store. Browse products by point range, select items, and complete checkout. Points are deducted immediately, and you\'ll receive order confirmation via email.', '2026-01-13 04:17:01'),
(12, 'Redemption', 'What is the conversion rate for points?', '2 Points = ₹1. For example, a product worth ₹500 would cost 1,000 points in the merch store.', '2026-01-13 04:17:01'),
(13, 'Redemption', 'What rewards can I redeem?', 'Rewards are categorized by point ranges: 100-500 points (small gifts, merchandise, vouchers), 501-1,500 (showpieces, mid-range merchandise), 1,501-3,500 (gadgets, premium gifts), 3,501-7,500 (high-value items), 7,501-15,000 (high-end gadgets), 15,001-30,000 (exclusive experiences), 30,001-50,000 (company-sponsored trips, very high-value gifts).', '2026-01-13 04:17:01'),
(14, 'Redemption', 'Can I exchange points for cash?', 'No, points cannot be exchanged for money. They can only be redeemed for gifts or vouchers from the merch store, which are non-transferable.', '2026-01-13 04:17:01'),
(15, 'Points Expiry', 'Do my points expire?', 'Yes, all points expire on January 1st each year. The system encourages usage, not hoarding as well as a fresh start. You\'ll receive alerts when points are expiring within 30 days.', '2026-01-13 04:17:01'),
(16, 'Points Expiry', 'Can expired points be restored?', 'No, expired points cannot be restored. Make sure to use your points before they expire by redeeming rewards from the merch store.', '2026-01-13 04:17:01'),
(17, 'Leaderboard', 'How does the monthly leaderboard work?', 'The leaderboard displays the top 10 earners for the current month with their rank, name, department, and points. You can filter by department, sangh, or view overall rankings. If you\'re not in the top 10, your personal rank is displayed at the top.', '2026-01-13 04:17:01'),
(18, 'Leaderboard', 'What are the badges on the leaderboard?', 'Top 3 ranks receive badges: Gold (1st place), Silver (2nd place), and Bronze (3rd place). Your lifetime badge count shows how many times you\'ve achieved top 3 positions throughout your tenure.', '2026-01-13 04:17:01'),
(19, 'Rules & Policies', 'What happens if I exceed 50,000 points?', 'If you exceed 50,000 points before the year ends, additional points become bonus/overflow points. You can bring multiple gifts from the merch store, but overflow points don\'t carry over to the next year.', '2026-01-13 04:17:01'),
(20, 'Rules & Policies', 'Are all transactions visible?', 'Yes, all transactions are logged and visible on the point system portal for complete transparency. Monthly statements are accessible to all members, and you can export your transaction history to PDF or Excel.', '2026-01-13 04:17:01'),
(21, 'Rules & Policies', 'What happens if there is bias or manipulation?', 'Any cheating, manipulation, or bias in point allocation will lead to review and deductions. Leaders must distribute points fairly and cannot favor the same members repeatedly. The system has built-in anomaly detection.', '2026-01-13 04:17:01'),
(22, 'Rules & Policies', 'How do I raise a dispute?', 'Disputes must be raised within a defined timeframe through the portal. System admin and management will review the case, and their decisions are final.', '2026-01-13 04:17:01'),
(23, 'Technical', 'Can I access RPS from mobile?', 'Yes, the RPS portal is fully responsive and accessible from mobile devices, tablets, and desktops. Use your regular TeamYPL credentials to login.', '2026-01-13 04:17:01'),
(24, 'Technical', 'What should I do if I can\'t access the portal?', 'Ensure you\'re using your correct employee ID and password. If issues persist, contact IT support or system admin. Never share your credentials with others.', '2026-01-13 04:17:01'),
(25, 'Technical', 'How often is the dashboard updated?', 'Your dashboard updates in real-time. Points balance, transaction history, and leaderboard rankings are immediately reflected when changes occur.', '2026-01-13 04:17:01');
